import React, { createContext, useContext, useEffect, useMemo, useReducer } from 'react';
import { View, Text, TextInput, TouchableOpacity, ActivityIndicator, StyleSheet, SafeAreaView } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const AUTH_STORAGE_KEY = '@mvp_auth';

const AuthContext = createContext(null);

const initialState = {
  isLoading: true,
  isAuthenticated: false,
  token: null,
  user: null,
  error: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_SESSION':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: !!action.payload?.token,
        token: action.payload?.token || null,
        user: action.payload?.user || null,
        error: null,
      };
    case 'LOGIN_SUCCESS':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: true,
        token: action.payload.token,
        user: action.payload.user,
        error: null,
      };
    case 'LOGIN_ERROR':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: false,
        token: null,
        user: null,
        error: action.payload || 'Login failed',
      };
    case 'LOGOUT':
      return {
        ...state,
        isLoading: false,
        isAuthenticated: false,
        token: null,
        user: null,
        error: null,
      };
    case 'SET_LOADING':
      return {
        ...state,
        isLoading: action.payload,
      };
    default:
      return state;
  }
}

async function persistSession(session) {
  await AsyncStorage.setItem(AUTH_STORAGE_KEY, JSON.stringify(session));
}

async function clearSession() {
  await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
}

async function restoreSession() {
  const raw = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch {
    await clearSession();
    return null;
  }
}

async function fakeLoginApi({ email, password }) {
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (!email || !password) {
    throw new Error('Email and password are required');
  }

  return {
    token: 'mock-token-' + Date.now(),
    user: {
      id: 'user_1',
      name: 'MVP User',
      email,
    },
  };
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let mounted = true;

    const bootstrap = async () => {
      try {
        const session = await restoreSession();
        if (mounted) {
          dispatch({ type: 'RESTORE_SESSION', payload: session });
        }
      } catch {
        if (mounted) {
          dispatch({ type: 'RESTORE_SESSION', payload: null });
        }
      }
    };

    bootstrap();

    return () => {
      mounted = false;
    };
  }, []);

  const auth = useMemo(
    () => ({
      ...state,
      login: async (email, password) => {
        dispatch({ type: 'SET_LOADING', payload: true });
        try {
          const result = await fakeLoginApi({ email, password });
          await persistSession(result);
          dispatch({ type: 'LOGIN_SUCCESS', payload: result });
        } catch (error) {
          await clearSession();
          dispatch({ type: 'LOGIN_ERROR', payload: error.message });
        }
      },
      logout: async () => {
        dispatch({ type: 'SET_LOADING', payload: true });
        await clearSession();
        dispatch({ type: 'LOGOUT' });
      },
    }),
    [state]
  );

  return <AuthContext.Provider value={auth}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

function SplashScreen() {
  return (
    <SafeAreaView style={styles.centered}>
      <ActivityIndicator size="large" />
      <Text style={styles.subtitle}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { login, isLoading, error } = useAuth();
  const [email, setEmail] = React.useState('');
  const [password, setPassword] = React.useState('');

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Sign In</Text>
        <TextInput
          value={email}
          onChangeText={setEmail}
          placeholder="Email"
          autoCapitalize="none"
          keyboardType="email-address"
          style={styles.input}
        />
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Password"
          secureTextEntry
          style={styles.input}
        />
        {error ? <Text style={styles.error}>{error}</Text> : null}
        <TouchableOpacity
          style={[styles.button, isLoading && styles.buttonDisabled]}
          onPress={() => login(email.trim(), password)}
          disabled={isLoading}
        >
          {isLoading ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Login</Text>}
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, logout, isLoading } = useAuth();

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.text}>Name: {user?.name}</Text>
        <Text style={styles.text}>Email: {user?.email}</Text>
        <Text style={styles.tokenLabel}>Token</Text>
        <Text style={styles.token}>{token}</Text>
        <TouchableOpacity
          style={[styles.button, styles.logoutButton, isLoading && styles.buttonDisabled]}
          onPress={logout}
          disabled={isLoading}
        >
          {isLoading ? <ActivityIndicator color="#fff" /> : <Text style={styles.buttonText}>Logout</Text>}
        </TouchableOpacity>
      </View>
    </SafeAreaView>
  );
}

function AuthGate() {
  const { isLoading, isAuthenticated } = useAuth();

  if (isLoading) {
    return <SplashScreen />;
  }

  return isAuthenticated ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

